<script lang="ts">
	import { billingState } from './billing-state.svelte'
	import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '$lib/components/ui/card'
	import D3CumulativeBarChart from './d3-cumulative-bar-chart.svelte'

	interface Props {
		organizationId: number
	}

	let { organizationId }: Props = $props()

	$effect(() => {
		billingState.loadProjections(organizationId)
	})

	function formatDate(dateStr: string | null): string {
		if (!dateStr) return 'N/A'
		return new Date(dateStr).toLocaleDateString('en-US', {
			year: 'numeric',
			month: 'short',
			day: 'numeric'
		})
	}
</script>

<Card>
	<CardHeader>
		<CardTitle>Usage Projections</CardTitle>
		<CardDescription>
			Billing period: {formatDate(billingState.projections?.period_start ?? null)} - {formatDate(billingState.projections?.period_end ?? null)}
		</CardDescription>
	</CardHeader>
	<CardContent>
		{#if billingState.projectionsLoading}
			<div class="text-muted-foreground">Loading usage data...</div>
		{:else if billingState.projectionsError}
			<div class="text-destructive">{billingState.projectionsError}</div>
		{:else if billingState.projections}
			<div class="space-y-6">
				<!-- Usage chart -->
				{#if billingState.projections.daily_usage.length > 0}
					<D3CumulativeBarChart
						data={billingState.projections.daily_usage}
						planLimit={billingState.projections.plan_limit}
					/>
				{:else}
					<div class="py-8 text-center text-muted-foreground">
						No usage data available for this billing period yet.
					</div>
				{/if}
			</div>
		{/if}
	</CardContent>
</Card>
