import { api } from "$lib/api";

export interface BillingInfo {
  plan: string;
  status: string;
  current_period_start: string | null;
  current_period_end: string | null;
  cancel_at_period_end: boolean;
  stripe_customer_id: string;
}

export interface DailyUsagePoint {
  date: string;
  daily_usage: number;
  cumulative_usage: number;
  is_projected: boolean;
}

export interface BillingProjections {
  period_start: string | null;
  period_end: string | null;
  plan_limit: number;
  plan: string;
  daily_usage: DailyUsagePoint[];
  total_usage: number;
  days_remaining: number;
  projected_usage: number;
}

export interface PlanConfig {
  id: string;
  name: string;
  limits: string;
  price: string;
  priceValue: number;
}

export const PLANS: PlanConfig[] = [
  {
    id: "free",
    name: "Starter",
    limits: "10k issues, requests, task runs",
    price: "Free",
    priceValue: 0,
  },
  {
    id: "pro",
    name: "Pro",
    limits: "100k issues, requests, task runs",
    price: "$12.99/month",
    priceValue: 12.99,
  },
  {
    id: "premium",
    name: "Premium",
    limits: "1mil issues, requests, task runs",
    price: "$24.99/month",
    priceValue: 24.99,
  },
  {
    id: "enterprise",
    name: "Enterprise",
    limits: "200mil issues, requests, task runs",
    price: "$499.99/month",
    priceValue: 499.99,
  },
];

class BillingState {
  subscription = $state<BillingInfo | null>(null);
  loading = $state(false);
  error = $state<string | null>(null);

  projections = $state<BillingProjections | null>(null);
  projectionsLoading = $state(false);
  projectionsError = $state<string | null>(null);

  async loadBilling(organizationId: number) {
    this.loading = true;
    this.error = null;
    try {
      this.subscription = await api.get<BillingInfo>(
        `/organizations/${organizationId}/billing`,
      );
    } catch (e) {
      this.error = e instanceof Error ? e.message : "Failed to load billing";
    } finally {
      this.loading = false;
    }
  }

  async loadProjections(organizationId: number) {
    this.projectionsLoading = true;
    this.projectionsError = null;
    try {
      this.projections = await api.get<BillingProjections>(
        `/organizations/${organizationId}/billing/projections`,
      );
    } catch (e) {
      this.projectionsError =
        e instanceof Error ? e.message : "Failed to load projections";
    } finally {
      this.projectionsLoading = false;
    }
  }

  async createCheckoutSession(
    organizationId: number,
    plan: string,
    successUrl: string,
    cancelUrl: string,
  ): Promise<string | null> {
    try {
      const response = await api.post<{ url: string }>(
        `/organizations/${organizationId}/billing/checkout`,
        {
          plan,
          success_url: successUrl,
          cancel_url: cancelUrl,
        },
      );
      return response.url;
    } catch (e) {
      this.error =
        e instanceof Error ? e.message : "Failed to create checkout session";
      return null;
    }
  }

  async createPortalSession(
    organizationId: number,
    returnUrl: string,
  ): Promise<string | null> {
    try {
      const response = await api.post<{ url: string }>(
        `/organizations/${organizationId}/billing/portal`,
        {
          return_url: returnUrl,
        },
      );
      return response.url;
    } catch (e) {
      this.error =
        e instanceof Error ? e.message : "Failed to create portal session";
      return null;
    }
  }

  get isPro(): boolean {
    return this.subscription?.plan === "pro";
  }

  get isPaidPlan(): boolean {
    const plan = this.subscription?.plan;
    return plan === "pro" || plan === "premium" || plan === "enterprise";
  }

  get planDisplayName(): string {
    switch (this.subscription?.plan) {
      case "pro":
        return "Pro";
      case "premium":
        return "Premium";
      case "enterprise":
        return "Enterprise";
      default:
        return "Free";
    }
  }

  isCurrentPlan(planId: string): boolean {
    return this.subscription?.plan === planId;
  }

  isUpgrade(planId: string): boolean {
    const currentPlan = PLANS.find((p) => p.id === this.subscription?.plan);
    const targetPlan = PLANS.find((p) => p.id === planId);
    if (!currentPlan || !targetPlan) return false;
    return targetPlan.priceValue > currentPlan.priceValue;
  }
}

export const billingState = new BillingState();
