<script lang="ts">
	import { scaleBand, scaleLinear } from 'd3-scale'
	import { max } from 'd3-array'
	import type { DailyUsagePoint } from './billing-state.svelte'

	interface Props {
		data: DailyUsagePoint[]
		planLimit: number
		height?: number
	}

	let { data, planLimit, height = 200 }: Props = $props()

	let containerElement: HTMLDivElement
	let containerWidth = $state(600)

	$effect(() => {
		if (containerElement) {
			const observer = new ResizeObserver((entries) => {
				containerWidth = entries[0].contentRect.width
			})
			observer.observe(containerElement)
			return () => observer.disconnect()
		}
	})

	let svgElement: SVGSVGElement
	let tooltipVisible = $state(false)
	let tooltipX = $state(0)
	let tooltipY = $state(0)
	let tooltipData = $state<DailyUsagePoint | null>(null)

	const margin = { top: 10, right: 60, bottom: 40, left: 10 }

	const minBarHeight = 4 // minimum bar height in pixels for visibility
	const zeroUsageColor = '#e5e7eb' // light grey for zero usage days
	const actualBarColor = '#3b82f6' // blue
	const projectedBarColor = '#d1d5db' // grey

	function formatNumber(num: number): string {
		if (num >= 1000000) return `${(num / 1000000).toFixed(1)}M`
		if (num >= 1000) return `${(num / 1000).toFixed(0)}K`
		return num.toString()
	}

	function formatAxisDate(dateStr: string): string {
		const date = new Date(dateStr)
		const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec']
		return `${months[date.getMonth()]} ${date.getDate()}`
	}

	const innerWidth = $derived(containerWidth - margin.left - margin.right)
	const innerHeight = $derived(height - margin.top - margin.bottom)

	const xScale = $derived(
		scaleBand<string>()
			.domain(data.map(d => d.date))
			.range([0, innerWidth])
			.padding(0.2)
	)

	const yMax = $derived(Math.max(planLimit * 1.1, max(data, d => d.cumulative_usage) || 0))

	const yScale = $derived(
		scaleLinear()
			.domain([0, yMax])
			.nice()
			.range([innerHeight, 0])
	)

	const xAxisTicks = $derived(() => {
		const interval = Math.ceil(data.length / 7)
		return data.filter((_, i) => i % interval === 0).map(d => d.date)
	})

	function handleMouseEnter(point: DailyUsagePoint) {
		tooltipData = point
		tooltipVisible = true
		updateTooltipPosition(point)
	}

	function handleMouseLeave() {
		tooltipVisible = false
		tooltipData = null
	}

	function formatTooltipDate(dateStr: string): string {
		const date = new Date(dateStr)
		return date.toLocaleDateString('en-US', {
			weekday: 'short',
			month: 'short',
			day: 'numeric',
			year: 'numeric'
		})
	}

	function updateTooltipPosition(point: DailyUsagePoint) {
		const x = xScale(point.date) || 0
		const barTop = yScale(point.cumulative_usage)
		tooltipX = margin.left + x + xScale.bandwidth() / 2
		tooltipY = margin.top + barTop - 8
	}
</script>

<div bind:this={containerElement} class="chart-container relative w-full">
	<svg bind:this={svgElement} width={containerWidth} {height}>
		<g transform="translate({margin.left},{margin.top})">
			<!-- X axis -->
			<g class="x-axis" transform="translate(0,{innerHeight})">
				<line x1="0" x2={innerWidth} stroke="#e5e7eb" />
				{#each xAxisTicks() as tick}
					{@const x = (xScale(tick) || 0) + xScale.bandwidth() / 2}
					<g transform="translate({x},0)">
						<text
							y="12"
							text-anchor="end"
							transform="rotate(-45)"
							fill="#6b7280"
							font-size="11"
						>
							{formatAxisDate(tick)}
						</text>
					</g>
				{/each}
			</g>

			<!-- Plan limit line -->
			<line
				x1="0"
				x2={innerWidth}
				y1={yScale(planLimit)}
				y2={yScale(planLimit)}
				stroke="#9ca3af"
				stroke-width="1"
				stroke-dasharray="4,4"
			/>
			<!-- Limit label on right side -->
			<text
				x={innerWidth + 8}
				y={yScale(planLimit)}
				dy="0.35em"
				text-anchor="start"
				fill="#6b7280"
				font-size="12"
			>
				{formatNumber(planLimit)}
			</text>

			<!-- Bars -->
			{#each data as point}
				{@const x = xScale(point.date) || 0}
				{@const calculatedHeight = innerHeight - yScale(point.cumulative_usage)}
				{@const barHeight = Math.max(minBarHeight, calculatedHeight)}
				{@const barColor = point.cumulative_usage === 0
					? zeroUsageColor
					: point.is_projected
						? projectedBarColor
						: actualBarColor}
				<rect
					{x}
					y={innerHeight - barHeight}
					width={xScale.bandwidth()}
					height={barHeight}
					fill={barColor}
					rx="2"
					class="cursor-pointer transition-opacity hover:opacity-80"
					onmouseenter={() => handleMouseEnter(point)}
					onmouseleave={handleMouseLeave}
				/>
			{/each}
		</g>
	</svg>

	<!-- Tooltip -->
	{#if tooltipVisible && tooltipData}
		<div
			class="absolute pointer-events-none px-3 py-2 rounded-lg text-xs z-10 shadow-lg border -translate-x-1/2 -translate-y-full bg-white dark:bg-gray-800 text-gray-900 dark:text-gray-100 border-gray-200 dark:border-gray-700 whitespace-nowrap"
			style="left: {tooltipX}px; top: {tooltipY}px;"
		>
			<div class="font-medium">{formatTooltipDate(tooltipData.date)}{tooltipData.is_projected ? ' (projected)' : ''}</div>
			<div class="text-muted-foreground">Daily: {formatNumber(tooltipData.daily_usage)}</div>
			<div class="text-muted-foreground">Cumulative: {formatNumber(tooltipData.cumulative_usage)}</div>
		</div>
	{/if}
</div>

<style>
	.chart-container {
		width: 100%;
		overflow: visible;
	}
</style>
