<script lang="ts">
	import { billingState, PLANS } from './billing-state.svelte'
	import { Button } from '$lib/components/ui/button'
	import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '$lib/components/ui/card'
	import { Check } from 'lucide-svelte';
	import BillingProjectionsCard from './billing-projections-card.svelte'

	interface Props {
		organizationId: number
	}

	let { organizationId }: Props = $props()

	$effect(() => {
		billingState.loadBilling(organizationId)
	})

	async function handleSelectPlan(planId: string) {
		const successUrl = `${window.location.origin}/settings?billing=success`
		const cancelUrl = `${window.location.origin}/settings?billing=canceled`
		const url = await billingState.createCheckoutSession(organizationId, planId, successUrl, cancelUrl)
		if (url) {
			window.location.href = url
		}
	}

	async function handleManageSubscription() {
		const returnUrl = `${window.location.origin}/settings`
		const url = await billingState.createPortalSession(organizationId, returnUrl)
		if (url) {
			window.location.href = url
		}
	}

	async function handleRowClick(planId: string) {
		const isCurrent = billingState.isCurrentPlan(planId)
		const isUpgrade = billingState.isUpgrade(planId)

		if (isCurrent) {
			await handleManageSubscription()
		} else if (isUpgrade) {
			await handleSelectPlan(planId)
		} else {
			await handleManageSubscription()
		}
	}

	function formatDate(dateStr: string | null): string {
		if (!dateStr) return 'N/A'
		return new Date(dateStr).toLocaleDateString('en-US', {
			year: 'numeric',
			month: 'long',
			day: 'numeric'
		})
	}
</script>

<Card>
	<CardHeader class="flex flex-row items-center justify-between">
		<div>
			<CardTitle>Billing</CardTitle>
			<CardDescription>Manage your subscription and billing</CardDescription>
		</div>
		{#if billingState.subscription?.stripe_customer_id}
			<Button variant="default" onclick={handleManageSubscription}>
				Manage Subscription
			</Button>
		{/if}
	</CardHeader>
	<CardContent>
		{#if billingState.loading}
			<div class="text-muted-foreground">Loading billing information...</div>
		{:else if billingState.error}
			<div class="text-destructive">{billingState.error}</div>
		{:else if billingState.subscription}
			<div class="space-y-4">
				{#if billingState.isPaidPlan && billingState.subscription.current_period_end}
					<p class="text-sm text-muted-foreground">
						{#if billingState.subscription.cancel_at_period_end}
							Access ends: {formatDate(billingState.subscription.current_period_end)}
						{:else}
							Next billing date: {formatDate(billingState.subscription.current_period_end)}
						{/if}
					</p>
				{/if}

				<div class="space-y-3">
					{#each PLANS as plan}
						{@const isCurrent = billingState.isCurrentPlan(plan.id)}
						{@const isCancelled = isCurrent && billingState.subscription?.cancel_at_period_end}
						<div
							class="p-4 rounded-lg cursor-pointer transition-colors
								{isCurrent
								? 'bg-white border-2 border-green-500'
								: 'bg-gray-100 dark:bg-gray-800 hover:bg-gray-200 dark:hover:bg-gray-700'}"
							onclick={() => handleRowClick(plan.id)}
							onkeydown={(e) => e.key === 'Enter' && handleRowClick(plan.id)}
							role="button"
							tabindex="0"
						>
							<div class="flex items-center justify-between">
								<div class="flex items-center gap-2">
									{#if isCurrent}
										<div class="w-5 h-5 bg-green-500 rounded-full flex items-center justify-center shrink-0">
											<Check class="w-3 h-3 text-white" />
										</div>
									{/if}
									<span class="font-semibold">{plan.name}</span>
									{#if isCancelled}
										<span class="px-2 py-0.5 text-xs font-medium bg-amber-100 text-amber-800 rounded-full">
											Cancelled
										</span>
									{/if}
								</div>
								<span class="font-medium">{plan.price}</span>
							</div>
							<p class="text-sm text-muted-foreground mt-1">{plan.limits}</p>
						</div>
					{/each}
				</div>
			</div>
		{/if}
	</CardContent>
</Card>

<BillingProjectionsCard {organizationId} />
